def seed_megaprompts_from_files(apps, schema_editor):
    """For each domain still without an active MegaPrompt, create one from its seed file.

    Runs after 0024_migrate_globalsettings_to_megaprompt — which may already have
    created PRE_CALL/POST_CALL rows from legacy GlobalSettings content. This step
    fills any remaining gaps so every domain has an active row after `migrate`,
    with no manual `seed_mega_prompts` command needed.

    Version assignment mirrors the seed_mega_prompts command: max(version)+1 per domain,
    so we don't clash with any prior (inactive) versions that might already exist.
    """
    MegaPrompt = apps.get_model("voice", "MegaPrompt")

    for domain, filename in DOMAIN_TO_FILENAME.items():
        if MegaPrompt.objects.filter(domain=domain, is_active=True).exists():
            continue

        seed_path = SEED_DIR / filename
        if not seed_path.exists():
            # Fail loud. Seed files are committed alongside this migration and
            # must exist at `migrate` time. Silently skipping would leave the
            # domain with zero active rows, and the PR 2 assembler's
            # `.filter(is_active=True).first()` would later return None
            # without an obvious cause.
            raise FileNotFoundError(
                f"MegaPrompt seed file missing for domain {domain}: {seed_path}. "
                f"This file must exist for migration 0025 to bootstrap the system. "
                f"If you intentionally removed seed files, also remove or update "
                f"this migration."
            )

        content = seed_path.read_text(encoding="utf-8")
        if not content.strip():
            raise ValueError(
                f"MegaPrompt seed file for domain {domain} is empty: {seed_path}. "
                f"An empty meta-prompt would render the assembler non-functional "
                f"for this domain."
            )

        max_v = (
            MegaPrompt.objects.filter(domain=domain).aggregate(Max("version"))["version__max"] or 0
        )
        new_version = max_v + 1

        MegaPrompt.objects.create(
            domain=domain,
            name=f"Seeded v{new_version} (from seed file)",
            meta_prompt=content,
            is_active=True,
            version=new_version,
        )


